    summary: { points: ["AD-AS determines GDP and price level for the whole economy", "AD shifts from changes in spending, taxes, money supply", "AS shifts from costs, technology, labor supply", "Stagflation: the worst combo — falling output + rising prices"], quote: { text: "Economics is not about goods and services; it is about human choice and action.", author: "Ludwig von Mises" } },
